/**
 * Expandable section customization for UI
 */
export interface UiExpandableSectionCustomization {
    /**
     * The description
     */
    description?: string;
    /**
     * The display name
     */
    displayName: string;
    /**
     * Defines if the section should be expanded by default
     */
    expanded?: boolean;
    /**
     * A list of properties
     */
    properties: string[];
}
